// Representation of Linear Memory in JS
const memory = new WebAssembly.Memory({ initial: 10, maximum: 100 });
const buffer = new Uint8Array(memory.buffer);

// Rust pointer (u32) simply points to an index here
// If Rust returns pointer '1024', JS reads:
// buffer.slice(1024, 1024 + length)

// Configuring a custom allocator
// Cargo.toml: features = ["wee_alloc"]

#[global_allocator]
static ALLOC: wee_alloc::WeeAlloc = wee_alloc::WeeAlloc::INIT;

use wasm_bindgen::JsCast;
use web_sys::{HtmlCanvasElement, HtmlDivElement};

fn handle_element(element: HtmlDivElement) {
    // Upcasting to Node (Automatic via Deref or explicit AsRef)
    let node: &web_sys::Node = element.as_ref();

    // Trying to cast generic Element to Canvas
    // Equivalent to JS: if (element instanceof HTMLCanvasElement)
    if let Ok(canvas) = element.dyn_into::<HtmlCanvasElement>() {
        // Now we have canvas methods
        canvas.get_context("2d").unwrap();
    }
}

